import { useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { toast } from 'sonner';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { EmptyState } from '@/components/data/EmptyState';
import { ApiError } from '@/lib/api';
import { formatDateTime } from '@/lib/format';
import {
  useApprovalDetailQuery,
  useApproveQueryChange,
  useRejectQueryChange,
} from './queries';

const STATUS_LABEL: Record<number, string> = {
  0: 'Pending',
  1: 'Approved',
  2: 'Rejected',
  3: 'Cancelled',
};

export default function ApprovalDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const numericId = id ? Number.parseInt(id, 10) : Number.NaN;

  const detail = useApprovalDetailQuery(Number.isFinite(numericId) ? numericId : undefined);
  const approve = useApproveQueryChange();
  const reject = useRejectQueryChange();
  const [comment, setComment] = useState('');

  if (Number.isNaN(numericId)) {
    return (
      <div className="page">
        <PageHeader title="Approval" />
        <EmptyState icon={<Icon.Alert size={20} />} title="Invalid approval id" description={String(id)} />
      </div>
    );
  }

  const handleAction = async (action: 'approve' | 'reject') => {
    try {
      const trimmed = comment.trim() || null;
      if (action === 'approve') {
        await approve.mutateAsync({ id: numericId, comment: trimmed });
        toast.success('Approval granted');
      } else {
        await reject.mutateAsync({ id: numericId, comment: trimmed });
        toast.success('Approval rejected');
      }
      navigate('/approvals');
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Action failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  const data = detail.data;
  const isPending = data?.status === 0;
  const busy = approve.isPending || reject.isPending;

  return (
    <div className="page">
      <PageHeader
        title={data?.queryName ? `Approval: ${data.queryName}` : 'Approval'}
        sub={
          <span className="muted">
            <Link to="/approvals" className="muted">Approvals</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            #{numericId}
          </span>
        }
        actions={
          <Link className="btn" to="/approvals">
            <Icon.ArrowsLR size={14} className="btn__icon" />
            All approvals
          </Link>
        }
      />

      {detail.isLoading && (
        <div className="card">
          <div className="card__body"><span className="muted">Loading approval…</span></div>
        </div>
      )}

      {detail.isError && (
        <EmptyState
          icon={<Icon.Alert size={20} />}
          title="Failed to load approval"
          description={detail.error instanceof Error ? detail.error.message : 'Unknown error'}
        />
      )}

      {data && (
        <>
          <div className="card" style={{ marginBottom: 16 }}>
            <div className="card__body">
              <h3 className="card__title" style={{ margin: '0 0 12px' }}>
                <Icon.Layers size={14} /> Request
              </h3>
              <dl style={{ display: 'grid', gridTemplateColumns: '180px 1fr', rowGap: 8, columnGap: 12, margin: 0 }}>
                <dt className="muted">Query</dt>
                <dd>
                  {data.queryId
                    ? <Link to={`/queries/${data.queryId}`} style={{ fontWeight: 600 }}>{data.queryName}</Link>
                    : <span style={{ fontWeight: 600 }}>{data.queryName}</span>}
                </dd>
                <dt className="muted">Status</dt>
                <dd>
                  <span className={data.status === 0 ? 'pill' : data.status === 1 ? 'pill pill--ok' : 'pill'}>
                    {STATUS_LABEL[data.status ?? 0] ?? `status ${data.status}`}
                  </span>
                </dd>
                <dt className="muted">Submitted by</dt>
                <dd>{data.requestedByUserName ?? <span className="muted">Unknown</span>}</dd>
                <dt className="muted">Submitted at</dt>
                <dd className="mono">{data.createdTime ? formatDateTime(data.createdTime as unknown as string) : '—'}</dd>
                {data.reviewedByUserName && (
                  <>
                    <dt className="muted">Reviewed by</dt>
                    <dd>{data.reviewedByUserName}</dd>
                  </>
                )}
                {data.reviewedAt && (
                  <>
                    <dt className="muted">Reviewed at</dt>
                    <dd className="mono">{formatDateTime(data.reviewedAt as unknown as string)}</dd>
                  </>
                )}
                {data.reviewComment && (
                  <>
                    <dt className="muted">Reviewer comment</dt>
                    <dd>{data.reviewComment}</dd>
                  </>
                )}
                <dt className="muted">Change summary</dt>
                <dd>{data.changeSummary ?? <span className="muted">—</span>}</dd>
              </dl>
            </div>
          </div>

          {data.proposedVersion?.finalQuery && (
            <div className="card" style={{ marginBottom: 16 }}>
              <div className="card__body">
                <h3 className="card__title" style={{ margin: '0 0 12px' }}>
                  <Icon.Database size={14} /> Proposed SQL
                </h3>
                <pre style={{
                  background: 'var(--surface-2)',
                  border: '1px solid var(--border)',
                  borderRadius: 'var(--r-sm)',
                  padding: 12,
                  fontSize: 12,
                  margin: 0,
                  whiteSpace: 'pre-wrap',
                  overflow: 'auto',
                  maxHeight: 400,
                }}>{data.proposedVersion.finalQuery}</pre>
              </div>
            </div>
          )}

          {data.currentActiveVersion?.finalQuery && data.currentActiveVersion.finalQuery !== data.proposedVersion?.finalQuery && (
            <div className="card" style={{ marginBottom: 16 }}>
              <div className="card__body">
                <h3 className="card__title" style={{ margin: '0 0 12px' }}>
                  <Icon.Database size={14} /> Current active SQL
                </h3>
                <pre style={{
                  background: 'var(--surface-2)',
                  border: '1px solid var(--border)',
                  borderRadius: 'var(--r-sm)',
                  padding: 12,
                  fontSize: 12,
                  margin: 0,
                  whiteSpace: 'pre-wrap',
                  overflow: 'auto',
                  maxHeight: 400,
                }}>{data.currentActiveVersion.finalQuery}</pre>
              </div>
            </div>
          )}

          {isPending && (
            <div className="card" style={{ marginBottom: 16 }}>
              <div className="card__body">
                <h3 className="card__title" style={{ margin: '0 0 12px' }}>
                  <Icon.Check size={14} /> Decision
                </h3>
                <div className="q-field">
                  <label className="q-label" htmlFor="ad-comment">Reviewer comment (optional)</label>
                  <textarea
                    id="ad-comment"
                    rows={3}
                    className="q-input"
                    placeholder="Optional note shown alongside your decision."
                    value={comment}
                    onChange={e => setComment(e.target.value)}
                  />
                </div>
                <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 12 }}>
                  <button
                    type="button"
                    className="btn btn--danger"
                    onClick={() => handleAction('reject')}
                    disabled={busy}
                  >
                    {reject.isPending ? 'Rejecting…' : 'Reject'}
                  </button>
                  <button
                    type="button"
                    className="btn btn--primary"
                    onClick={() => handleAction('approve')}
                    disabled={busy}
                  >
                    {approve.isPending ? 'Approving…' : 'Approve'}
                  </button>
                </div>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}
